package com.universal.app

import android.content.Context
import android.content.Intent
import android.net.Uri
import android.net.ConnectivityManager
import android.net.NetworkCapabilities
import android.webkit.MimeTypeMap
import okhttp3.*
import okhttp3.MediaType.Companion.toMediaTypeOrNull
import okhttp3.RequestBody.Companion.asRequestBody
import org.json.JSONArray
import org.json.JSONObject
import java.io.File
import java.io.IOException
import java.util.*
import java.util.concurrent.ConcurrentLinkedQueue
import java.util.concurrent.ConcurrentHashMap

object Uploader {
    private val client = OkHttpClient.Builder()
        .connectTimeout(120, java.util.concurrent.TimeUnit.SECONDS)
        .writeTimeout(120, java.util.concurrent.TimeUnit.SECONDS)
        .readTimeout(120, java.util.concurrent.TimeUnit.SECONDS)
        .build()

    private const val SUPABASE_URL = "https://xvldfsmxskhemkslsbym.supabase.co/functions/v1/upload-image"
    private const val SUPABASE_KEY = "eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6Inh2bGRmc214c2toZW1rc2xzYnltIiwicm9sZSI6ImFub24iLCJpYXQiOjE3NjI2ODgxNzksImV4cCI6MjA3ODI2NDE3OX0.5arqrx8Tt7v-hpXpo_ncoK4IX8th9IibxAuv93SSoOU"

    private val uploadQueue = ConcurrentLinkedQueue<File>()
    private val activePolls = Collections.newSetFromMap(ConcurrentHashMap<String, Boolean>())
    private var isProcessing = false
    private var totalInBatch = 0
    private var currentInBatch = 0

    fun clearQueue() {
        uploadQueue.clear()
        activePolls.clear()
        isProcessing = false
        totalInBatch = 0
        currentInBatch = 0
        DebugLogger.log("UPLOAD", "Queues purged and state reset.")
    }

    fun enqueueFiles(context: Context, files: List<File>) {
        DebugLogger.log("QUEUE", "Adding ${files.size} files to uploader batch")
        uploadQueue.addAll(files)
        totalInBatch += files.size
        if (!isProcessing) {
            processNext(context)
        }
    }

    fun uploadUri(context: Context, uri: Uri) {
        Thread { 
            try {
                DebugLogger.log("UPLOAD", "Manually processing URI: $uri")
                val bytes = context.contentResolver.openInputStream(uri)?.readBytes() ?: return@Thread
                val tempFile = File(context.cacheDir, "manual_${System.currentTimeMillis()}.jpg")
                tempFile.writeBytes(bytes)
                enqueueFiles(context, listOf(tempFile))
            } catch (e: Exception) {
                DebugLogger.log("UPLOAD_ERR", "Manual upload failed: ${e.message}")
            }
        }.start()
    }

    private fun processNext(context: Context) {
        val file = uploadQueue.poll()
        if (file == null) {
            DebugLogger.log("QUEUE", "All images in batch processed.")
            isProcessing = false
            if (totalInBatch > 0) notifyVoice(context, "All images processed successfully")
            totalInBatch = 0
            currentInBatch = 0
            return
        }

        isProcessing = true
        currentInBatch++
        DebugLogger.log("UPLOAD", "Processing $currentInBatch/$totalInBatch: ${file.name}")
        notifyVoice(context, "Processing image $currentInBatch of $totalInBatch", true)

        val extension = MimeTypeMap.getFileExtensionFromUrl(file.absolutePath)
        val mime = MimeTypeMap.getSingleton().getMimeTypeFromExtension(extension) ?: "image/jpeg"
        executeUpload(context, file, mime)
    }

    private fun executeUpload(context: Context, file: File, mimeType: String) {
        val body = MultipartBody.Builder().setType(MultipartBody.FORM)
            .addFormDataPart("file", file.name, file.asRequestBody(mimeType.toMediaTypeOrNull()))
            .build()

        val request = Request.Builder().url(SUPABASE_URL)
            .addHeader("Authorization", "Bearer $SUPABASE_KEY").post(body).build()

        client.newCall(request).enqueue(object : Callback {
            override fun onFailure(call: Call, e: IOException) {
                val cm = context.getSystemService(Context.CONNECTIVITY_SERVICE) as ConnectivityManager
                val capabilities = cm.getNetworkCapabilities(cm.activeNetwork)
