149 |                 // Append 'L' for Long, 'S' for Short to the sequence string
150 |                 gestureSequence += if (duration > 600) "L" else "S"
151 |                 
152 |                 handler.postDelayed(headsetGestureRunnable, 450)
153 |                 return true
154 |             }
155 |         }
156 | 
157 |         // 3. Volume Key DOWN Logic
158 |         if (action == KeyEvent.ACTION_DOWN) {
159 |             val now = System.currentTimeMillis()
160 |             if (keyCode == KeyEvent.KEYCODE_VOLUME_UP) {
161 |                 isVolUpPressed = true
162 |                 isWaitingForTapHold = (now - lastUpTime < 800)
163 |             }
164 |             if (keyCode == KeyEvent.KEYCODE_VOLUME_DOWN) {
165 |                 isVolDownPressed = true
166 |                 isWaitingForDownTapHold = (now - lastDownTime < 800)
167 |             }
168 | 
169 |             if (event.repeatCount > 0) return true
170 |             if (isVolUpPressed && isVolDownPressed) return true
171 | 
172 |             when (keyCode) {
173 |                 KeyEvent.KEYCODE_VOLUME_UP -> {
174 |                     if (event.repeatCount == 0) {
175 |                         isLongPressTriggered = false
176 |                         handler.postDelayed(volUpLongPressRunnable, 5000)
177 |                     }
178 |                     val now = System.currentTimeMillis()
179 |                     if (now - lastUpTime < CLICK_GAP) upCount++ else upCount = 1
180 |                     lastUpTime = now
181 |                     return true
182 |                 }
183 |                 KeyEvent.KEYCODE_VOLUME_DOWN -> {
184 |                     if (event.repeatCount == 0) {
185 |                         isLongPressTriggered = false
186 |                         handler.postDelayed(volDownBatchRunnable, 5000)
187 |                     }
188 |                     val now = System.currentTimeMillis()
189 |                     if (now - lastDownTime < CLICK_GAP) downCount++ else downCount = 1
190 |                     lastDownTime = now
191 |                     return true
192 |                 }
193 |             }
194 |         }
195 | 
196 |         // 4. Volume Key UP Logic
197 |         if (action == KeyEvent.ACTION_UP) {
198 |             val wasBothPressed = isVolUpPressed && isVolDownPressed
199 |             if (keyCode == KeyEvent.KEYCODE_VOLUME_UP) isVolUpPressed = false
200 |             if (keyCode == KeyEvent.KEYCODE_VOLUME_DOWN) isVolDownPressed = false
201 | 
202 |             if (wasBothPressed) {
203 |                 val intent = Intent(this, PlaybackService::class.java)
204 |                 intent.action = if (isLongPress) "RESET" else "PAUSE"
205 |                 startService(intent)
206 |                 return true
207 |             }
208 | 
209 | 
210 | 
211 |             when (keyCode) {
212 |                 KeyEvent.KEYCODE_VOLUME_UP -> {
213 |                     handler.removeCallbacks(volUpLongPressRunnable)
214 |                     if (isLongPressTriggered) {
215 |                         isLongPressTriggered = false
216 |                         upCount = 0
217 |                         isWaitingForTapHold = false
218 |                         return true
219 |                     }
220 |                     
221 |                     val duration = event.eventTime - event.downTime
222 |                     if (isWaitingForTapHold && duration > 500) {
223 |                         toggleCamera()
224 |                         isWaitingForTapHold = false
225 |                         upCount = 0 
226 |                         return true 
227 |                     }
228 |                     isWaitingForTapHold = false
229 |                     handlePress("UP", upCount, isLongPress)
230 |                 }
231 |                 KeyEvent.KEYCODE_VOLUME_DOWN -> {
232 |                     handler.removeCallbacks(volDownBatchRunnable)
233 |                     if (isLongPressTriggered) return true
234 |                     
235 |                     val duration = event.eventTime - event.downTime
236 |                     if (isWaitingForDownTapHold && duration > 500) {
237 |                         triggerReset()
238 |                         isWaitingForDownTapHold = false
239 |                         downCount = 0
240 |                         return true
241 |                     }
242 |                     isWaitingForDownTapHold = false
243 |                     handlePress("DOWN", downCount, isLongPress)
244 |                 }
245 |             }
246 |             return true
247 |         }
248 | 
249 |         return super.onKeyEvent(event)
250 |     }
