351 |     private fun prepareWideLens(): Boolean {
352 |         val root = rootInActiveWindow ?: return false
353 |         
354 |         var lensNode: AccessibilityNodeInfo? = null
355 |         val searchTerms = listOf(".5", "0.5", "0,5", "0.6", "0.5x", "0,5x", "ultra", "wide", "zoom out")
356 |         val bounds = Rect()
357 | 
358 |         val queue = LinkedList<AccessibilityNodeInfo>()
359 |         queue.add(root)
360 |         while (!queue.isEmpty()) {
361 |             val node = queue.poll() ?: continue
362 |             val text = node.text?.toString()?.lowercase() ?: ""
363 |             val desc = node.contentDescription?.toString()?.lowercase() ?: ""
364 |             
365 |             val match = searchTerms.find { (text.contains(it) || desc.contains(it)) && !text.contains("1x") }
366 | 
367 |             if (match != null) {
368 |                 var current: AccessibilityNodeInfo? = node
369 |                 var depth = 0
370 |                 while (current != null && depth < 6) {
371 |                     if (current.isClickable) {
372 |                         lensNode = current
373 |                         break
374 |                     }
375 |                     current = current.parent
376 |                     depth++
377 |                 }
378 |                 if (lensNode != null) break
379 |             }
380 |             for (i in 0 until node.childCount) { node.getChild(i)?.let { queue.add(it) } }
381 |         }
382 | 
383 |         return if (lensNode != null) {
384 |             // Try Virtual Click first (Robust Verification)
385 |             val success = lensNode.performAction(AccessibilityNodeInfo.ACTION_CLICK)
386 |             
387 |             if (success) {
388 |                 DebugLogger.log("LENS_FLOW", "Virtual click SUCCESS")
389 |                 speak("Wide lens activated", true)
390 |                 hapticPulse(50)
391 |                 true
392 |             } else {
393 |                 // Fallback to Physical Tap for Samsung/Google Camera
394 |                 lensNode.getBoundsInScreen(bounds)
395 |                 val x = bounds.centerX().toFloat()
396 |                 val y = bounds.centerY().toFloat()
397 |                 
398 |                 val clickPath = Path().apply { moveTo(x, y) }
399 |                 val gesture = GestureDescription.Builder()
400 |                     .addStroke(GestureDescription.StrokeDescription(clickPath, 0, 50))
401 |                     .build()
402 |                 
403 |                 dispatchGesture(gesture, null, null)
404 |                 DebugLogger.log("LENS_FLOW", "Virtual click REJECTED. Physical tap dispatched to $x, $y")
405 |                 // Return false so the retry loop continues to verify the switch
406 |                 false
407 |             }
408 |         } else {
409 |             false
410 |         }
411 |     }
