413 |     private fun attemptLensSwitch(retries: Int) {
414 |         if (!isLensSwitchPending) return
415 |         
416 |         if (retries <= 0) {
417 |             DebugLogger.log("LENS_FLOW", "Search timed out. Applying fallback coordinates.")
418 |             clickLensCoordinatesFallback()
419 |             isLensSwitchPending = false
420 |             val prefs = getSharedPreferences("monitor_prefs", Context.MODE_PRIVATE)
421 |             if (prefs.getBoolean("touch_blocker", false)) showTouchBlocker()
422 |             return
423 |         }
424 | 
425 |         handler.postDelayed({
426 |             if (!isLensSwitchPending) return@postDelayed
427 |             
428 |             val success = prepareWideLens()
429 |             if (success) {
430 |                 DebugLogger.log("LENS_FLOW", "Lens switch CONFIRMED.")
431 |                 isLensSwitchPending = false
432 |                 val prefs = getSharedPreferences("monitor_prefs", Context.MODE_PRIVATE)
433 |                 if (prefs.getBoolean("touch_blocker", false)) showTouchBlocker()
434 |             } else {
435 |                 attemptLensSwitch(retries - 1)
436 |             }
437 |         }, 500)
438 |     }
