454 |     private fun performPinchFallback() {
455 |         val metrics = resources.displayMetrics
456 |         val centerX = metrics.widthPixels / 2f
457 |         val centerY = metrics.heightPixels / 2f
458 |         val path1 = android.graphics.Path().apply { moveTo(100f, 100f); lineTo(centerX - 50, centerY - 50) }
459 |         val path2 = android.graphics.Path().apply { moveTo(metrics.widthPixels - 100f, 100f); lineTo(centerX + 50, centerY - 50) }
460 |         val stroke1 = GestureDescription.StrokeDescription(path1, 0, 500)
461 |         val stroke2 = GestureDescription.StrokeDescription(path2, 0, 500)
462 |         val gesture = GestureDescription.Builder().addStroke(stroke1).addStroke(stroke2).build()
463 |         
464 |         dispatchGesture(gesture, object : AccessibilityService.GestureResultCallback() {
465 |             override fun onCompleted(gestureDescription: GestureDescription) = DebugLogger.log("GESTURE", "Pinch SUCCESS")
466 |             override fun onCancelled(gestureDescription: GestureDescription) = DebugLogger.log("GESTURE", "Pinch FAILED")
467 |         }, null)
468 |     }
