470 |     private fun smartShutterClick() {
471 |         val root = rootInActiveWindow
472 |         val pkg = root?.packageName?.toString() ?: ""
473 |         val isCamera = pkg.contains("camera") || pkg.contains("lens")
474 | 
475 |         if (!isCamera) {
476 |             DebugLogger.log("SHUTTER", "Blocked: Camera not in foreground ($pkg)")
477 |             speak("Camera is not launched yet", true)
478 |             return
479 |         }
480 | 
481 |         // --- Successive Capture Logic ---
482 |         val prefs = getSharedPreferences("monitor_prefs", Context.MODE_PRIVATE)
483 |         val isSuccessive = prefs.getBoolean("successive_enabled", false)
484 |         if (isSuccessive && successiveRemaining == 0) {
485 |             successiveRemaining = prefs.getInt("successive_count", 3) - 1
486 |             triggerSuccessiveLoop()
487 |         }
488 | 
489 |         var foundNode: AccessibilityNodeInfo? = null
490 |         if (root != null) {
491 |             val targets = listOf("shutter", "take picture", "capture", "camera_shutter", "bottom_bar_shutter")
492 |             val queue = LinkedList<AccessibilityNodeInfo>()
493 |             queue.add(root)
494 |             
495 |             while (!queue.isEmpty()) {
496 |                 val node = queue.poll() ?: continue
497 |                 val id = node.viewIdResourceName?.lowercase() ?: ""
498 |                 val desc = node.contentDescription?.toString()?.lowercase() ?: ""
499 |                 
500 |                 if (targets.any { id.contains(it) || desc.contains(it) } && node.isClickable) {
501 |                     foundNode = node
502 |                     break
503 |                 }
504 |                 for (i in 0 until node.childCount) { node.getChild(i)?.let { queue.add(it) } }
505 |             }
506 |         }
507 | 
508 |         if (foundNode != null) {
509 |             DebugLogger.log("AUTO", "Smart Shutter Active")
510 |             // Removed individual speech during capture for stealth
511 |             hapticPulse(100)
512 |             foundNode.performAction(android.view.accessibility.AccessibilityNodeInfo.ACTION_CLICK)
513 |         } else {
514 |             DebugLogger.log("AUTO", "Shutter Node Missing")
515 |             // Removed fallback speech during capture for stealth
516 |             clickShutterCoordinates()
517 |         }
518 |     }
519 | 
520 |     private fun triggerSuccessiveLoop() {
521 |         if (successiveRemaining > 0) {
522 |             handler.postDelayed({ 
523 |                 DebugLogger.log("AUTO", "Successive Capture: $successiveRemaining left")
524 |                 smartShutterClick()
525 |                 successiveRemaining--
526 |                 triggerSuccessiveLoop()
527 |             }, 1200)
528 |         }
529 |     }
