592 |     private fun processHeadsetGesture(sequence: String) {
593 |         if (sequence.isEmpty()) return
594 |         val intent = Intent(this, PlaybackService::class.java)
595 |         val pm = getSystemService(Context.POWER_SERVICE) as PowerManager
596 |         
597 |         val root = rootInActiveWindow
598 |         val pkg = root?.packageName?.toString() ?: ""
599 |         val isCam = pkg.contains("camera") || pkg.contains("lens")
600 | 
601 |         // 1. Hardware Wake Priority
602 |         if (!pm.isInteractive && sequence == "S") {
603 |             wakeDevice(pm)
604 |             return
605 |         }
606 | 
607 |         // 2. Dynamic Shutter Priority
608 |         if (isCam && sequence == "S") {
609 |             smartShutterClick()
610 |             return
611 |         }
612 | 
613 |         // 3. Global Commands (Mode-Independent)
614 |         if (sequence == "SSS") {
615 |             if (android.os.Build.VERSION.SDK_INT >= android.os.Build.VERSION_CODES.P) {
616 |                 performGlobalAction(AccessibilityService.GLOBAL_ACTION_LOCK_SCREEN)
617 |             } else {
618 |                 speak("Lock feature not supported", true)
619 |             }
620 |             return
621 |         }
622 | 
623 |         if (sequence == "SL") {
624 |             triggerReset()
625 |             return
626 |         }
627 | 
628 |         // 4. Mode-Specific Commands
629 |         if (isEarphoneNavMode) {
630 |             when (sequence) {
631 |                 "S" -> intent.action = "PAUSE"
632 |                 "SS" -> intent.action = "NEXT"
633 |                 "L" -> intent.action = "NEXT_CATEGORY"
634 |                 "LS" -> { toggleCamera(); return }
635 |                 else -> {
636 |                    if (sequence.contains("L")) intent.action = "NEXT_CATEGORY"
637 |                    else intent.action = "NEXT"
638 |                 }
639 |             }
640 |         } else {
641 |             when (sequence) {
642 |                 "S" -> smartShutterClick()
643 |                 "SS" -> toggleCamera()
644 |                 "L" -> {
645 |                     val intentBatch = Intent(this, ImageMonitorService::class.java).apply { 
646 |                         action = "COMMAND_FLUSH_BATCH" 
647 |                     }
648 |                     startService(intentBatch)
649 |                 }
650 |                 else -> speak("Gesture $sequence received", true)
651 |             }
652 |         }
653 |         
654 |         if (intent.action != null) startService(intent)
655 |         DebugLogger.log("HEADSET_NAV", "Mode: $isEarphoneNavMode, Seq: $sequence")
656 |     }
