665 |     private fun recursiveLog(node: AccessibilityNodeInfo, depth: Int) {
666 |         if (depth > 15) return
667 |         val sb = StringBuilder()
668 |         repeat(depth) { sb.append(".") }
669 |         
670 |         val text = node.text?.toString() ?: ""
671 |         val desc = node.contentDescription?.toString() ?: ""
672 |         val id = node.viewIdResourceName ?: ""
673 |         val bounds = Rect()
674 |         node.getBoundsInScreen(bounds)
675 | 
676 |         sb.append("[").append(node.className?.toString()?.split(".")?.last() ?: "Unknown").append("] ")
677 |         if (text.isNotEmpty()) sb.append("T:$text ")
678 |         if (desc.isNotEmpty()) sb.append("D:$desc ")
679 |         if (id.isNotEmpty()) sb.append("ID:$id ")
680 |         sb.append("B:(${bounds.left},${bounds.top})")
681 |         
682 |         if (node.isClickable || text.contains("0") || desc.contains("0")) {
683 |              DebugLogger.log("UI_TRACE", sb.toString())
684 |         }
685 |         
686 |         for (i in 0 until node.childCount) {
687 |             node.getChild(i)?.let { recursiveLog(it, depth + 1) }
688 |         }
