691 |     override fun onAccessibilityEvent(event: AccessibilityEvent?) {
692 |         val type = event?.eventType
693 |         val pkg = event?.packageName?.toString() ?: ""
694 |         val isCam = pkg.contains("camera") || pkg.contains("lens")
695 |         val isSystemUI = pkg == "com.android.systemui"
696 | 
697 |         // 1. Dynamic Blocker Toggle (Notification Shade Awareness)
698 |         if (blockerOverlay != null) {
699 |             val localPrefs = getSharedPreferences("monitor_prefs", Context.MODE_PRIVATE)
700 |             val protocolActive = localPrefs.getBoolean("engage_protocol", false)
701 |             if (isSystemUI && !protocolActive) {
702 |                 // Only allow hiding blocker for notifications if NOT in Engage Protocol
703 |                 blockerOverlay?.visibility = View.GONE
704 |                 DebugLogger.log("BLOCKER", "System UI: Hiding overlay")
705 |             } else {
706 |                 // In Engage Protocol, blocker is ALWAYS visible even over System UI
707 |                 blockerOverlay?.visibility = View.VISIBLE
708 |             }
709 |         }
710 | 
711 |         // 0. Engage Protocol Enforcement
712 |         val prefs = getSharedPreferences("monitor_prefs", Context.MODE_PRIVATE)
713 |         if (prefs.getBoolean("engage_protocol", false) && blockerOverlay == null) {
714 |             showTouchBlocker()
715 |         }
716 | 
717 |         if (isCam) {
718 |             if (!prefs.getBoolean("is_active", false)) return
719 | 
720 |             if (type == AccessibilityEvent.TYPE_WINDOW_STATE_CHANGED || 
721 |                (type == AccessibilityEvent.TYPE_WINDOW_CONTENT_CHANGED && isLensSwitchPending)) {
722 |                 if (lastCameraPackage != pkg || !isLensSwitchPending) {
723 |                     lastCameraPackage = pkg
724 |                     isLensSwitchPending = true
725 |                     DebugLogger.log("AUTO_CAM", "Camera Session Initiated: $pkg")
726 |                     speak("Optimizing camera settings", true)
727 |                     attemptLensSwitch(25)
728 |                 }
729 |             }
730 |         } else if (type == AccessibilityEvent.TYPE_WINDOW_STATE_CHANGED) {
731 |             // Stickier Context Check: Only remove blocker if we are SURE we left the camera.
732 |             val isPersistentSystem = pkg == "android" || pkg == "com.android.systemui"
733 |             
734 |             // Verify the ACTUAL root package to avoid being fooled by transient overlays
735 |             val activeRoot = rootInActiveWindow?.packageName?.toString() ?: ""
