if (isCam && (keyCode == KeyEvent.KEYCODE_VOLUME_UP || keyCode == KeyEvent.KEYCODE_VOLUME_DOWN)) {
    if (action == KeyEvent.ACTION_UP) {
        val now = System.currentTimeMillis()

        if (keyCode == KeyEvent.KEYCODE_VOLUME_UP) {
            // Detect Double-Tap to CLOSE
            if (now - lastUpTime < 400) {
                // Cancel any pending shutter from the first tap
                pendingShutterAction?.let { handler.removeCallbacks(it) }
                pendingShutterAction = null

                DebugLogger.log("CAM_FLOW", "Double-tap detected: Closing Camera.")
                hapticPulse(100)
                toggleCamera() // This will close the camera since it's already open
                lastUpTime = 0 // Reset
                return true
            }
            lastUpTime = now
        }

        // Debounced Shutter: Wait to ensure it's not a double-tap
        pendingShutterAction?.let { handler.removeCallbacks(it) }
        val shutterTask = Runnable {
            DebugLogger.log("SHUTTER", "Single tap confirmed: Capturing.")
            smartShutterClick()
            pendingShutterAction = null
        }
        pendingShutterAction = shutterTask
        handler.postDelayed(shutterTask, 350)
        return true 
    }
    return false
}

